INSERT INTO compliance_rules (framework_short,rule_id,description,regex_pattern,url_check,severity,citation_url,enforcement_example,rule_type,trigger_pattern,fine_low_gbp,fine_high_gbp,layman_explanation,tamazia_fix_short,service_page_path,pricing_tier,active,sector_relevance,created_at) VALUES
('EU_AI_ACT','AIACT_CHATBOT_DISCLOSE','Disclose to users when they are interacting with an AI system','(you are (chatting|speaking) with (an )?ai|ai (assistant|chatbot|powered)|automated (assistant|system)|this is an ai)','homepage','P1','https://eur-lex.europa.eu/eli/reg/2024/1689/oj','EU AI Act Art. 50 transparency duties apply from 2025; the Act carries the highest tech-law fine ceiling, EUR 35M or 7% of global turnover.','trigger_then_check','(intercom|drift|tidio|chatbot|live ?chat|ai assistant|gpt|virtual assistant)',NULL,NULL,'The EU AI Act requires you to tell EU users when they are interacting with an AI chatbot rather than a human. Your AI widget does not disclose this.','Tamazia adds a clear AI-interaction disclosure to the chatbot for EU users.','/services/compliance','scale',TRUE,NULL,now()),
('EU_AI_ACT','AIACT_GENAI_LABEL','Label AI-generated or manipulated content','(ai[- ]generated|generated by ai|synthetic (media|content)|created with ai)','homepage','P2','https://eur-lex.europa.eu/eli/reg/2024/1689/oj','EU AI Act Art. 50 requires AI-generated content shown to EU users to be labelled as such.','trigger_then_check','(ai[- ]generated|midjourney|dall-?e|stable diffusion|synthetic|deepfake|generated image)',NULL,NULL,'AI-generated images or content shown to EU users must be labelled under the EU AI Act. Yours is not.','Tamazia labels AI-generated content to meet EU AI Act transparency.','/services/compliance','scale',TRUE,NULL,now()),
('EU_DSA','DSA_TRADER_ID','Trader identification + contact for EU online sales','(company (registration|number)|registered (office|address)|vat (number|id)|trader (details|information))','homepage','P2','https://eur-lex.europa.eu/eli/reg/2022/2065/oj','EU DSA requires clear trader identity and contact for EU consumers; the Commission has opened DSA proceedings against major platforms.','trigger_then_check','(add to (cart|basket)|checkout|buy now|marketplace|seller|online (shop|store))',NULL,NULL,'The EU Digital Services Act requires online sellers to clearly identify the trader (name, address, registration, VAT) to EU consumers. Yours is missing or unclear.','Tamazia adds DSA-compliant trader identification to the store.','/services/compliance','scale',TRUE,'{ecommerce,retail,saas}',now()),
('EU_DSA','DSA_TERMS_CLEAR','Clear, accessible terms of service for EU users','(terms (of (service|use)|and conditions)|user agreement)','homepage','P3','https://eur-lex.europa.eu/eli/reg/2022/2065/oj','EU DSA Art. 14 requires clear terms setting out content + moderation rules for services to EU users.','trigger_then_check','(add to (cart|basket)|account|sign ?up|upload|post a|community)',NULL,NULL,'The EU DSA requires clear, accessible terms of service. Yours are absent or not surfaced.','Tamazia publishes DSA-compliant terms of service.','/services/compliance','scale',TRUE,'{ecommerce,saas,media}',now()),
('EU_EAA_2025','EAA_ALT_TEXT','Text alternatives for non-text content (WCAG 1.1.1)','(alt=|aria-label|alt text|text alternative)','homepage','P2','https://eur-lex.europa.eu/eli/dir/2019/882/oj','EU Accessibility Act (enforced 28 Jun 2025) adopts WCAG 2.1 AA via EN 301 549; member states fine up to EUR 300k.','trigger_then_check','(add to (cart|basket)|checkout|book (online|now)|online (store|booking)|sign ?up)',4300,258000,'WCAG 2.1 AA (required by the EU Accessibility Act for EU-facing services) needs text alternatives for images and controls. Your site is missing them.','Tamazia adds alt text and ARIA labelling across the site.','/services/compliance','scale',TRUE,'{ecommerce,retail,hospitality,finance,saas}',now()),
('EU_EAA_2025','EAA_KEYBOARD','Full keyboard operability (WCAG 2.1.1)','(skip to (content|main)|keyboard (accessible|navigation)|tabindex|focus[- ]visible)','homepage','P2','https://eur-lex.europa.eu/eli/dir/2019/882/oj','EU Accessibility Act requires keyboard operability under WCAG 2.1 AA.','trigger_then_check','(add to (cart|basket)|checkout|book (online|now)|menu|navigation)',4300,258000,'EU accessibility rules require the whole site to work by keyboard alone. Key interactions on your site appear mouse-only.','Tamazia makes all interactions fully keyboard-operable.','/services/compliance','scale',TRUE,'{ecommerce,retail,hospitality,finance,saas}',now()),
('UK_SRA_TRANSPARENCY','SRA_PRICE_PUBLISH','Publish prices for the listed services (SRA Transparency Rules)','(our (fees|prices|charges)|price(s)? (from|start)|fixed fee|hourly rate|cost of)','homepage','P1','https://www.sra.org.uk/solicitors/guidance/price-transparency/','SRA Transparency Rules 2018 mandate published prices for specified services; SRA website sweeps found most firms non-compliant.','trigger_then_check','(solicitor|conveyanc|probate|immigration|employment tribunal|debt recovery|licensing)',NULL,NULL,'The SRA Transparency Rules require law firms to publish prices for the listed services (conveyancing, probate, immigration, employment, licensing, debt recovery). Your site does not.','Tamazia publishes an SRA-compliant price and service-information section.','/services/compliance','scale',TRUE,'{legal,law-firms}',now()),
('UK_SRA_TRANSPARENCY','SRA_COMPLAINTS','Complaints procedure + Legal Ombudsman + SRA routes','(complaints (procedure|policy)|legal ombudsman|how to complain|raise a complaint)','homepage','P1','https://www.sra.org.uk/solicitors/standards-regulations/','SRA Standards require a published complaints procedure with Legal Ombudsman and SRA escalation routes.','trigger_then_check','(solicitor|law firm|legal services|barrister)',NULL,NULL,'The SRA requires a published complaints procedure naming the Legal Ombudsman and SRA routes. Yours is missing.','Tamazia adds the SRA-compliant complaints procedure.','/services/compliance','scale',TRUE,'{legal,law-firms}',now()),
('UK_SRA_TRANSPARENCY','SRA_REGULATORY_INFO','Regulatory information + SRA number + clickable SRA badge','(authorised and regulated by the (solicitors regulation authority|sra)|sra (number|no|id)|sra-?\d{5,})','homepage','P2','https://www.sra.org.uk/solicitors/standards-regulations/','SRA rules require firms to show their SRA number, the regulated-by statement, and the SRA digital badge.','trigger_then_check','(solicitor|law firm|legal services|barrister)',NULL,NULL,'The SRA requires the "authorised and regulated by the SRA", the SRA number, and the clickable SRA digital badge. Your site lacks them.','Tamazia adds the SRA regulatory block and digital badge.','/services/compliance','scale',TRUE,'{legal,law-firms}',now()),
('UK_FSMA_S21','FCA_RISK_WARNING','Risk warning on investment/financial promotions','(capital (at risk|is at risk)|you (may|could) (lose|get back less)|investments? can (go down|fall)|not (fscs )?protected|past performance)','homepage','P1','https://www.fca.org.uk/firms/financial-promotions-and-adverts','FCA rules require prominent risk warnings on financial promotions; the FCA forced thousands of non-compliant promotions to be amended or withdrawn in 2024-25.','trigger_then_check','(invest|return(s)? of|portfolio|fund|crypto|trading|pension|isa|capital growth)',NULL,NULL,'FCA rules require a prominent risk warning on any investment promotion ("capital at risk"). Your financial promotion lacks it.','Tamazia adds FCA-compliant, prominent risk warnings to every financial promotion.','/services/compliance','scale',TRUE,'{financial,finance,fintech}',now()),
('UK_FSMA_S21','FCA_S21_APPROVAL','Section 21 approval / authorised-person status for promotions','(authorised and regulated by the (financial conduct authority|fca)|fca (number|no|reference)|approved by an authorised person)','homepage','P1','https://www.fca.org.uk/firms/financial-promotions-and-adverts','An unapproved financial promotion is a criminal offence under FSMA s.21 (up to 2 years imprisonment + unlimited fine).','trigger_then_check','(invest|return(s)?|fund|crypto|trading|pension|loan|credit|financial product)',NULL,NULL,'A financial promotion must be made or approved by an FCA-authorised person. There is no FCA authorisation/approval reference, which is a criminal offence under FSMA s.21.','Tamazia confirms FCA authorisation/approval and displays it on every promotion.','/services/compliance','scale',TRUE,'{financial,finance,fintech}',now()),
('UK_ASA_CAP','ASA_ENVIRONMENTAL','Substantiated, non-misleading environmental/green claims','(carbon (neutral|offset)|net zero|eco[- ]friendly|sustainable|green|recyclable|biodegradable)','homepage','P2','https://www.asa.org.uk/codes-and-rulings/advertising-codes.html','The ASA banned ads in 2025 for unsubstantiated green claims (e.g. Wizz Air); absolute environmental claims need a high level of substantiation.','trigger_then_check','(carbon (neutral|offset)|net zero|eco[- ]friendly|sustainable|recyclable|green credentials)',NULL,NULL,'The ASA requires environmental claims to be specific and substantiated. Your green/sustainability claims risk an ASA ruling unless evidenced.','Tamazia rewrites environmental claims to a substantiated, CAP-compliant form.','/services/compliance','scale',TRUE,NULL,now()),
('UK_ASA_CAP','ASA_URGENCY','No false urgency / misleading countdown timers','(genuine (offer|deadline)|while stocks last|offer ends)','homepage','P2','https://www.asa.org.uk/codes-and-rulings/advertising-codes.html','The ASA ruled against misleading countdown timers and false urgency in Oct 2025; the DMCC also bans false-urgency practices.','trigger_then_check','(countdown|hurry|only \d+ left|ends (today|soon|in)|limited time|last chance|selling fast)',NULL,NULL,'False-urgency tactics (fake countdowns, "only 2 left") breach the CAP Code and the DMCC Act. Your site uses urgency cues that must be genuine.','Tamazia removes false-urgency patterns and keeps only genuine, evidenced ones.','/services/compliance','scale',TRUE,'{ecommerce,retail,hospitality}',now()),
('UK_CQC','CQC_REGISTRATION','Display CQC registration for regulated healthcare activity','(cqc (registered|registration)|registered with the care quality commission|cqc (provider )?id)','homepage','P1','https://www.cqc.org.uk/guidance-providers/regulations','CQC registration is mandatory for regulated activities; the CQC prosecutes providers for misleading public information.','trigger_then_check','(clinic|gp|doctor|dental|care home|hospital|patient|treatment|medical)',NULL,NULL,'Providers of regulated healthcare must be CQC-registered and say so. Your site does not display CQC registration.','Tamazia adds the CQC registration statement and provider ID.','/services/compliance','scale',TRUE,'{healthcare,dental,medical}',now()),
('UK_CQC','CQC_RATING','Display the latest CQC rating accurately','(cqc (rating|rated)|rated (good|outstanding|requires improvement)|latest cqc)','homepage','P2','https://www.cqc.org.uk/guidance-providers/regulations','CQC requires providers to display their current rating accurately and prominently.','trigger_then_check','(clinic|gp|doctor|care home|hospital|patient)',NULL,NULL,'CQC-rated providers must display their latest rating accurately. Yours is missing or outdated.','Tamazia displays the current CQC rating per CQC display rules.','/services/compliance','scale',TRUE,'{healthcare,dental,medical}',now()),
('UK_EQUALITY_2010','EQA_ALT_TEXT','Image alt text as a reasonable adjustment','(alt=|aria-label|text alternative)','homepage','P2','https://www.equalityhumanrights.com/en/advice-and-guidance/website-accessibility','The Equality Act 2010 treats an inaccessible customer website as failing the reasonable-adjustment duty; claims are rising.','trigger_then_check','(our services|book|contact us|customers?|clients?|patients?|members)',NULL,NULL,'The Equality Act 2010 requires reasonable adjustments including accessible content (alt text). Your images lack it, which courts treat as discrimination.','Tamazia adds alt text and brings the site to WCAG 2.1 AA.','/services/compliance','scale',TRUE,NULL,now()),
('UK_CRA_2015','CRA_FAIR_TERMS','Fair, transparent and legible consumer contract terms','(terms (and conditions|of (sale|service))|fair (terms|processing)|plain (english|language))','homepage','P2','https://www.legislation.gov.uk/ukpga/2015/15/contents/enacted','Consumer Rights Act 2015: unfair or unintelligible terms are unenforceable and draw Trading Standards action.','trigger_then_check','(add to (cart|basket)|checkout|subscribe|buy now|sign ?up|membership)',NULL,NULL,'The Consumer Rights Act 2015 requires consumer terms to be fair and in plain language; unfair terms are unenforceable. Yours are missing or opaque.','Tamazia drafts fair, plain-language consumer terms.','/services/compliance','scale',TRUE,'{ecommerce,retail,hospitality,saas}',now()),
('UK_COMPANIES_ACT','CA_VAT_DISPLAY','VAT number displayed where VAT-registered','(vat (number|no|reg)|vat[- ]?registered|vat: ?gb\d)','homepage','P3','https://www.legislation.gov.uk/ukdsi/2015/9780111125892/contents','HMRC requires VAT-registered businesses to show the VAT number on their website and invoices.','trigger_then_check','(\bltd\b|limited\b|\bplc\b|prices|£\d|invoice|vat)',NULL,NULL,'If VAT-registered you must display your VAT number on the website. It is not shown.','Tamazia adds the VAT number to the footer and invoices.','/services/compliance','scale',TRUE,NULL,now()),
('UK_PECR','PECR_SOFT_OPTIN','Valid marketing consent or soft opt-in for email/SMS','(unsubscribe|opt[- ]?out|consent to (receive|marketing)|you can opt out|marketing preferences)','homepage','P2','https://ico.org.uk/for-organisations/direct-marketing-and-privacy-and-electronic-communications/guide-to-pecr/electronic-and-telephone-marketing/','PECR requires consent (or a valid soft opt-in) for electronic marketing; the ICO fines firms for non-compliant marketing.','trigger_then_check','(subscribe|newsletter|marketing|email updates|join our (list|mailing)|sms)',2000,17500000,'PECR requires consent or a valid soft opt-in for marketing email/SMS, with an easy opt-out. Your capture lacks a clear consent/opt-out.','Tamazia adds PECR-compliant consent and one-click opt-out to marketing capture.','/services/compliance','scale',TRUE,NULL,now())
